export const meta = {
  name: 'review-pr15-codetection',
  description: 'Adversarial multi-dimension review of PR #15 (codetection validation docs + experiment), with real command-running and skeptic verification of material findings',
  phases: [
    { title: 'Review', detail: 'one agent per dimension, each runs real checks on the branch' },
    { title: 'Verify', detail: 'skeptic re-checks each blocking/major finding' },
  ],
}

const REPO = '/home/ubuntu/Developer/repos/github.com/jakobtfaber/dsa110-FLITS'
const BRANCH = 'research/codetection-validation-rigor'

const COMMON = `You are reviewing PR #15 on branch ${BRANCH} in the repo ${REPO}.
The branch is checked out. Do REAL verification: actually RUN commands (Bash), Read files,
Grep code — do not reason from memory. Cite the exact command output as evidence for every
finding. Conda env 'casa6' (host python3) has numpy/astropy. Filter matplotlibrc warning noise.
The PR contains: three docs under .agents/ (research-codetection-validation-rigor.md,
experiment-chance-coincidence-falsealarm.md, plan-codetection-association-significance.md),
the experiment harness under .experiments/chance-coincidence/, and commit ab9d7f1 (the
chime_singlebeam reconciliation: crossmatching/chime_singlebeam.py + tests/test_chime_singlebeam_toa.py).
Severity scale: blocking (must fix before merge) | major | minor | nit | praise.
A claim that is wrong, an anchor that points at the wrong code, or a doc number that does not
reproduce is at least 'major'. Be specific and adversarial; do not rubber-stamp.`

const FINDINGS_SCHEMA = {
  type: 'object',
  required: ['dimension', 'ran', 'findings', 'verdict'],
  properties: {
    dimension: { type: 'string' },
    ran: { type: 'array', items: { type: 'string' }, description: 'commands/checks actually executed' },
    findings: {
      type: 'array',
      items: {
        type: 'object',
        required: ['severity', 'title', 'evidence', 'location'],
        properties: {
          severity: { type: 'string', enum: ['blocking', 'major', 'minor', 'nit', 'praise'] },
          title: { type: 'string' },
          evidence: { type: 'string', description: 'exact command output or file content proving it' },
          location: { type: 'string', description: 'file:line or doc section' },
          recommendation: { type: 'string' },
        },
      },
    },
    verdict: { type: 'string', enum: ['pass', 'changes-requested'] },
  },
}

const VERDICT_SCHEMA = {
  type: 'object',
  required: ['title', 'real', 'reasoning'],
  properties: {
    title: { type: 'string' },
    real: { type: 'boolean', description: 'true if the finding is genuinely a problem after independent re-check' },
    reasoning: { type: 'string', description: 'what command you ran to confirm/refute and what it showed' },
  },
}

const DIMENSIONS = [
  {
    key: 'experiment-reproducibility',
    prompt: `${COMMON}

DIMENSION: Experiment reproducibility (Iron Law). Actually RE-RUN the experiment and confirm the
numbers cited in .agents/experiment-chance-coincidence-falsealarm.md are REAL, not asserted.
  cd ${REPO}/.experiments/chance-coincidence && python3 run.py 2>&1 | grep -v -i 'matplotlibrc\\|prop_cycle'
Confirm against the doc: (a) per-burst analytic P ~ few e-9 and the specific values
(zach 6.263e-9, chromatica 6.330e-9, mahi 1.694e-9); (b) sum mu = 5.460e-08; (c) the A-vs-B
cross-validation: Analytic P=4.5006e-2 vs MC P=4.5129e-2 +/- 1.0e-4 (5 seeds), ratio 1.003;
(d) the robustness-sweep magnitudes. Flag ANY number in the doc that does not reproduce (allowing
tiny float/seed variation, which for the seeded MC should be exact). Also sanity-check that the MC
is genuinely seeded (deterministic) and that estimator_mc.py's repeat-index scatter is correct.`,
  },
  {
    key: 'research-anchor-accuracy',
    prompt: `${COMMON}

DIMENSION: Research-doc factual accuracy. For .agents/research-codetection-validation-rigor.md,
verify EVERY file:line anchor points at what the doc claims, using Read/Grep:
  - crossmatching/toa_crossmatch.py:99 compute_toa; :121 the K_DM shift; :128 compute_geometric_delay; :151 reproduce_notebook_result
  - crossmatching/plotting.py:84 residual; :90 error; :150 linregress
Then INDEPENDENTLY recompute the residual statistics the doc cites (mean +2.42 ms, std 3.06,
max |resid/err| = 2.79 at wilhelm, all within 3 sigma) directly from
crossmatching/toa_crossmatch_results.json with a python one-liner, and confirm. Flag any anchor
that is off by more than a couple lines or any statistic that does not reproduce. Also check the
external citations are real papers (Law et al. 2017 arXiv:1705.07553; Petroff et al. 2018
arXiv:1808.07809; CHIME/FRB Catalogue 1 Amiri 2021 ApJS 257 59) and not fabricated.`,
  },
  {
    key: 'plan-executability',
    prompt: `${COMMON}

DIMENSION: Plan executability & no-placeholders. For .agents/plan-codetection-association-significance.md:
(a) grep the plan for placeholder phrases (TBD, TODO, "implement later", "add appropriate",
"write tests for the above", "similar to phase") -- there must be NONE.
(b) Confirm the regression pin in Phase 1 is correct: run
  cd ${REPO}/.experiments/chance-coincidence && python3 -c "import inputs as I, estimator_analytic as A; print('%.6e' % A.mu_analytic(500.0, rate_per_day=1000.0, omega_win_deg2=I.OMEGA_WIN_BASELINE_DEG2, dt_s=1.0, ddm=5.0))" 2>&1 | grep -v -i matplotlibrc
  and check it equals the plan's pinned 5.023345e-09.
(c) Check internal consistency of the plan's embedded test/impl code: function names and signatures
  used in the test snippets (chance_mu, chance_probability, f_dm, expected_chance_associations,
  dm_agreement, timing_budget_ms, residual_pedestal, omega_disk_deg2, position_consistent,
  build_association_report) are all defined in some phase's implementation snippet; imports are
  coherent; no test references an undefined symbol.
(d) Confirm the integration anchors the plan cites still exist (crossmatching/toa_crossmatch.py:91-93
  CrossmatchResult fields; tests/test_crossmatching_notebook_reproduction.py:21). Flag mismatches.`,
  },
  {
    key: 'scientific-soundness',
    prompt: `${COMMON}

DIMENSION: Scientific/statistical soundness of the chance-coincidence formalism (read
.experiments/chance-coincidence/inputs.py, estimator_analytic.py, estimator_mc.py and the experiment doc).
Check: (a) mu = R_sr_s * Omega_win * (2*dt) * f_DM is dimensionally consistent (rate [sr^-1 s^-1] *
solid angle [sr] * time [s] * dimensionless = dimensionless expected count) -- verify the unit
conversions r_sr_s (per day -> per sr per s over 4pi) and omega_win_sr (deg^2 -> sr) are correct
numerically with a quick python check. (b) P = 1 - exp(-mu) is the right Poisson >=1 probability.
(c) Are the 'conservative' inputs actually chance-MAXIMISING as claimed (rate 1000 > catalogue 525;
generous 0.5deg window; +/-1s; +/-5 DM)? (d) Is the f_DM local-density approximation
(pdf*2*halfwidth, capped at 1) sound for the DM-match fraction, and does it cancel in the A-vs-B
ratio as the doc claims? Flag any genuine statistical error (not stylistic). Praise if correct.`,
  },
  {
    key: 'hygiene-consistency',
    prompt: `${COMMON}

DIMENSION: Hygiene, cross-doc consistency, and the bundled reconciliation. Checks:
(a) Run: cd ${REPO} && git diff --stat origin/main..HEAD ; git ls-files .experiments | grep -i pycache (must be empty -- no __pycache__/*.pyc committed).
(b) The reconciliation commit ab9d7f1 is bundled: confirm it is sound on this branch by running
  cd ${REPO} && python3 -m pytest tests/test_chime_singlebeam_toa.py -q 2>&1 | tail -5
  and  ruff check crossmatching/chime_singlebeam.py tests/test_chime_singlebeam_toa.py 2>&1 | tail -3
  -- both must pass/clean. Also confirm the existing reproduction test still passes:
  python3 -m pytest tests/test_crossmatching_notebook_reproduction.py -q 2>&1 | tail -5
(c) Cross-doc consistency: the research doc says '+2.4 ms pedestal', experiment/plan echo it -- ok.
  The reconciliation 'bit-exact 9/12' claim is consistent across docs. The plan says golden
  toa_crossmatch_results.json untouched -- confirm git shows it unmodified on this branch
  (git status --porcelain crossmatching/toa_crossmatch_results.json -> empty).
(d) Scan the diff for accidentally committed secrets or absolute-path leakage that shouldn't ship.
Flag real problems only.`,
  },
]

const results = await pipeline(
  DIMENSIONS,
  (d) => agent(d.prompt, { label: `review:${d.key}`, phase: 'Review', schema: FINDINGS_SCHEMA }),
  (review, d) => {
    if (!review) return { dimension: d.key, error: 'review agent died', findings: [] }
    const material = (review.findings || []).filter(f => f.severity === 'blocking' || f.severity === 'major')
    if (material.length === 0) return { ...review, verified: [] }
    return parallel(material.map(f => () =>
      agent(`${COMMON}

A reviewer of the '${d.key}' dimension raised this ${f.severity} finding on PR #15:
TITLE: ${f.title}
LOCATION: ${f.location}
EVIDENCE THEY GAVE: ${f.evidence}
RECOMMENDATION: ${f.recommendation || '(none)'}

Independently RE-CHECK it by running your own commands. Decide if it is REAL (a genuine problem
that should block or change the PR) or a false alarm. Default to real=false only if your own
command output contradicts the finding; quote that output in your reasoning.`,
        { label: `verify:${d.key}:${(f.title || '').slice(0, 30)}`, phase: 'Verify', schema: VERDICT_SCHEMA })
        .then(v => ({ ...f, verify: v }))
    )).then(verified => ({ ...review, verified }))
  }
)

return results.filter(Boolean)

